import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"茅盾故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/mao-dun-residence.md","filePath":"history/mao-dun-residence.md","lastUpdated":1784773307000}'),n={name:"history/mao-dun-residence.md"};function d(s,t,i,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="茅盾故居" tabindex="-1">茅盾故居 <a class="header-anchor" href="#茅盾故居" aria-label="Permalink to &quot;茅盾故居&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-Uk19VsygF9Y?w=1200" alt="茅盾故居"></p><blockquote><p>&quot;中国现代文学的奠基人，在胡同深处静静守望。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>茅盾故居位于北京市东城区后圆恩寺胡同13号，是一座典型的北京四合院。茅盾先生从1974年至1981年在此居住，度过了人生的最后7年。故居现已成为&quot;茅盾故居纪念馆&quot;，展示着这位文学巨匠的生平事迹和珍贵文物。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:00（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6/8号线南锣鼓巷站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区后圆恩寺胡同13号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="清代府邸" tabindex="-1">清代府邸 <a class="header-anchor" href="#清代府邸" aria-label="Permalink to &quot;清代府邸&quot;">​</a></h3><p>茅盾故居原为清代的一座四合院，后成为普通民居。1974年，茅盾先生迁入此院。</p><h3 id="茅盾晚年" tabindex="-1">茅盾晚年 <a class="header-anchor" href="#茅盾晚年" aria-label="Permalink to &quot;茅盾晚年&quot;">​</a></h3><p>1974年至1981年，茅盾先生在此居住，继续从事文学创作和学术研究。</p><h4 id="晚年成就" tabindex="-1">晚年成就 <a class="header-anchor" href="#晚年成就" aria-label="Permalink to &quot;晚年成就&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">成就</th></tr></thead><tbody><tr><td style="text-align:left;">1974年</td><td style="text-align:left;">迁入后圆恩寺胡同13号</td></tr><tr><td style="text-align:left;">1975年</td><td style="text-align:left;">继续创作回忆录</td></tr><tr><td style="text-align:left;">1981年</td><td style="text-align:left;">逝世于此</td></tr></tbody></table><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><h3 id="四合院结构" tabindex="-1">四合院结构 <a class="header-anchor" href="#四合院结构" aria-label="Permalink to &quot;四合院结构&quot;">​</a></h3><p>茅盾故居是一座典型的北京四合院，分为外院和内院。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大门</strong></td><td style="text-align:left;">入口</td><td style="text-align:left;">传统的朱漆大门</td></tr><tr><td style="text-align:left;"><strong>影壁</strong></td><td style="text-align:left;">照壁</td><td style="text-align:left;">简朴的砖雕影壁</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">茅盾居室</td><td style="text-align:left;">保留原貌</td></tr><tr><td style="text-align:left;"><strong>东厢房</strong></td><td style="text-align:left;">书房</td><td style="text-align:left;">茅盾生前书房</td></tr><tr><td style="text-align:left;"><strong>西厢房</strong></td><td style="text-align:left;">展览室</td><td style="text-align:left;">生平事迹展</td></tr></tbody></table><h3 id="主要展室" tabindex="-1">主要展室 <a class="header-anchor" href="#主要展室" aria-label="Permalink to &quot;主要展室&quot;">​</a></h3><h4 id="正房展室" tabindex="-1">正房展室 <a class="header-anchor" href="#正房展室" aria-label="Permalink to &quot;正房展室&quot;">​</a></h4><p>正房是茅盾先生的居室，保留了他生前的生活场景。</p><ul><li><strong>卧室</strong>：简朴的卧室，摆放着简朴的家具</li><li><strong>会客室</strong>：会客的地方，摆放着沙发和茶几</li><li><strong>工作室</strong>：茅盾生前工作的地方</li></ul><h4 id="西厢房展室" tabindex="-1">西厢房展室 <a class="header-anchor" href="#西厢房展室" aria-label="Permalink to &quot;西厢房展室&quot;">​</a></h4><p>西厢房是茅盾生平事迹展，展示了茅盾先生一生的重要经历。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><h3 id="手稿和著作" tabindex="-1">手稿和著作 <a class="header-anchor" href="#手稿和著作" aria-label="Permalink to &quot;手稿和著作&quot;">​</a></h3><p>茅盾故居收藏了大量茅盾先生的手稿和著作。</p><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>手稿</strong></td><td style="text-align:left;">《子夜》《春蚕》等手稿</td></tr><tr><td style="text-align:left;"><strong>著作</strong></td><td style="text-align:left;">各种版本的著作</td></tr><tr><td style="text-align:left;"><strong>书信</strong></td><td style="text-align:left;">与友人的往来书信</td></tr><tr><td style="text-align:left;"><strong>日记</strong></td><td style="text-align:left;">茅盾的日记</td></tr></tbody></table><h3 id="生活用品" tabindex="-1">生活用品 <a class="header-anchor" href="#生活用品" aria-label="Permalink to &quot;生活用品&quot;">​</a></h3><p>茅盾故居还保留了茅盾先生生前使用的生活用品。</p><ul><li><strong>家具</strong>：简朴的木质家具</li><li><strong>文具</strong>：笔、墨、纸、砚</li><li><strong>藏书</strong>：大量珍贵藏书</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 影壁 → 正房（茅盾居室） → 东厢房（书房） → 西厢房（生平展） → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前在官网或电话预约</li><li><strong>最佳时间</strong>：工作日人较少，适合慢慢参观</li><li><strong>拍照位置</strong>：影壁、正房前都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以租用讲解器，了解更多历史知识</li><li><strong>周边游览</strong>：参观完后可以到南锣鼓巷、什刹海游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">6/8号线南锣鼓巷站E口，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">13、60、82、107、124路南锣鼓巷站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;茅盾故居&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">网红胡同</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京水乡</td></tr><tr><td style="text-align:left;">钟鼓楼</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京地标</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>茅盾是中国现代文学史上的重要人物，他的小说《子夜》《春蚕》等在中国文学史上占有重要地位。茅盾故居不仅是一座名人故居，更是研究中国现代文学史的重要场所。</p><p>&quot;中国现代文学的奠基人&quot;，这个称号完美地概括了茅盾先生在中国文学史上的地位。</p><hr><p><strong>📍 地址</strong>：北京市东城区后圆恩寺胡同13号 <strong>🚇 地铁</strong>：6/8号线南锣鼓巷站E口 <strong>📞 电话</strong>：010-84015300</p><p><strong>💡 Tips</strong>：茅盾故居与南锣鼓巷相邻，可以安排在同一天参观。参观完后可以到南锣鼓巷逛逛特色小店。</p>',48)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
